update scm_supplier_certificate c
set c.status = '1', c.update_time = sysdate()
where c.supplier_id = #{supplierId}
  and (c.status is null or c.status != '1')

      and c.hospital_id = #{hospitalId}

  and c.certificate_id not in (
      select keep_id from (
          select min(c2.certificate_id) as keep_id
          from scm_supplier_certificate c2
          where c2.supplier_id = #{supplierId}
            and (c2.status is null or c2.status != '1')

                and c2.hospital_id = #{hospitalId}

          group by trim(c2.certificate_type), c2.hospital_id
      ) t
  )

update scm_supplier_certificate c
set c.hospital_id = #{hospitalId}, c.update_time = sysdate()
where c.supplier_id = #{supplierId}
  and c.hospital_id is null
  and (c.status is null or c.status != '1')
  and not exists (
      select 1 from (
          select 1 as one from scm_supplier_certificate x
          where x.supplier_id = #{supplierId}
            and x.hospital_id = #{hospitalId}
            and (x.status is null or x.status != '1')
      ) t
  )

